// src/components/Header.js
import React from 'react';
import './Header.css';

const Header = () => {
  return (
    <header className="header">
      <h1>Painel de Controle</h1>
      <div className="header-date">
        <span>03</span>
        <span>Outubro</span>
        <span>quinta-feira</span>
      </div>
    </header>
  );
};

export default Header;
